if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers['x-gda-auth'] || headers['x-gda-key'] || body.auth_key || body.deploy_key || '';
const origin = (headers.origin || headers.referer || headers['x-forwarded-host'] || '').toLowerCase();
const trustedOrigins = ['gda.csr-llc.tech', 'n8n.csr-llc.tech', 'localhost'];
const fromTrustedOrigin = trustedOrigins.some(function(o) { return origin.includes(o); });
if (auth !== $env.GDA_DEPLOY_KEY_2026 && auth !== $env.GDA_API_KEY_2026 && !fromTrustedOrigin) {
  throw new Error('Unauthorized');
}
return $input.all();

// Dual-write to pgvector — parallel path (Continue on Fail enabled)
const webhookData = $('Webhook').first().json;
const fileUrl = (webhookData.body && webhookData.body.attachments && webhookData.body.attachments[0]) 
  ? webhookData.body.attachments[0].url 
  : '';
const fileName = (webhookData.body && webhookData.body.attachments && webhookData.body.attachments[0])
  ? webhookData.body.attachments[0].name 
  : 'unknown';

if (!fileUrl) {
  return [{ json: { error: 'No file URL in webhook payload', skipped: true } }];
}

// Download file using n8n's built-in HTTP helper
let text = '';
try {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: fileUrl,
    encoding: 'utf-8',
    returnFullResponse: false,
  });
  text = typeof response === 'string' ? response : JSON.stringify(response);
  text = text.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, ' ').trim();
} catch (e) {
  return [{ json: { error: 'Download failed: ' + e.message, skipped: true } }];
}

if (!text || text.length < 10) {
  return [{ json: { error: 'Extracted text too short (' + text.length + ' chars)', skipped: true } }];
}

// Chunk text (2000 char chunks with 200 overlap)
const MAX_CHUNK = 2000;
const OVERLAP = 200;
const chunks = [];
for (let i = 0; i < text.length; i += MAX_CHUNK - OVERLAP) {
  const chunk = text.slice(i, i + MAX_CHUNK).trim();
  if (chunk.length > 10) chunks.push(chunk);
  if (chunks.length >= 50) break;
}

if (chunks.length === 0) {
  return [{ json: { error: 'No chunks generated', skipped: true } }];
}

// Generate embeddings via OpenAI
const openaiKey = $env.OPENAI_API_KEY;
if (!openaiKey) {
  return [{ json: { error: 'OPENAI_API_KEY not set', skipped: true } }];
}

const embResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.openai.com/v1/embeddings',
  headers: {
    'Authorization': 'Bearer ' + openaiKey,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    model: 'text-embedding-3-small',
    input: chunks
  }),
  returnFullResponse: false,
  json: true
});

if (!embResponse || !embResponse.data) {
  return [{ json: { error: 'OpenAI embedding failed', skipped: true } }];
}

const embeddings = embResponse.data.map(d => d.embedding);

// Build items
const docId = 'ai-upload-' + Date.now().toString(36);
const items = chunks.map((chunk, i) => ({
  id: docId + '_chunk_' + i,
  content: chunk,
  embedding: embeddings[i],
  metadata: {
    document_id: docId,
    chunk_index: i,
    source: fileUrl,
    file_name: fileName
  }
}));

// Call /vector-upsert
const upsertResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://gda-backend:3001/api/internal/vector-upsert',
  headers: {
    'Content-Type': 'application/json',
    'x-gda-key': $env.GDA_WEBHOOK_KEY
  },
  body: JSON.stringify({
    collection: 'ai-agent-attachments',
    items: items
  }),
  returnFullResponse: true,
  json: true
});

return [{ json: { 
  success: upsertResponse.statusCode >= 200 && upsertResponse.statusCode < 300, 
  chunks: chunks.length, 
  document_id: docId,
  status: upsertResponse.statusCode,
  response: upsertResponse.body
} }];

